23	type MongoCollection interface {
24		InsertOne(ctx context.Context, document any, opts ...*options.InsertOneOptions) (*mongo.InsertOneResult, error)
25		UpdateOne(ctx context.Context, filter any, update any, opts ...*options.UpdateOptions) (*mongo.UpdateResult, error)
26		FindOne(ctx context.Context, filter any, opts ...*options.FindOneOptions) *mongo.SingleResult
27		Find(ctx context.Context, filter any, opts ...*options.FindOptions) (cur *mongo.Cursor, err error)
28	}
