41	func NewStorage(ctx context.Context, mongo tmongo.Mongo) (*storage, error) {
42		db := &storage{
43			Mongo:               mongo,
44			handsetsCollection:  mongo.Client.Database(mongo.Database).Collection(collectionHandsets),
45			contractsCollection: mongo.Client.Database(mongo.Database).Collection(collectionContracts),
46		}
47	
48		err := db.ensureIndexes(ctx, mongo)
49		if err != nil {
50			return nil, err
51		}
52	
53		return db, nil
54	}
