56	func (s storage) ensureIndexes(ctx context.Context, mongoDb tmongo.Mongo) error {
57		err := tmongo.CreateIndexes(ctx, mongoDb, tmongo.CollectionIndexesMap{
58			collectionHandsets: {
59				mongo.IndexModel{
60					Keys:    bson.M{"id": 1},
61					Options: options.Index().SetName("id").SetUnique(true).SetSparse(true),
62				},
63				mongo.IndexModel{
64					Keys:    bson.M{"billID": 1},
65					Options: options.Index().SetName("bill_id").SetUnique(true).SetSparse(true),
66				},
67			},
68			collectionContracts: {
69				mongo.IndexModel{
70					Keys:    bson.M{"id": 1},
71					Options: options.Index().SetName("contract_id").SetUnique(true),
72				},
73				mongo.IndexModel{
74					Keys:    bson.M{"requestId": 1},
75					Options: options.Index().SetName("contract_request_id").SetUnique(true),
76				},
77				mongo.IndexModel{
78					Keys:    bson.M{"serviceId": 1},
79					Options: options.Index().SetName("contract_service_id"),
80				},
81			},
82		})()
83	
84		return err
85	}
