87	// UpsertHandset upserts a handset from the legacy equinoxdb/cron path (no versioning).
88	func (s storage) UpsertHandset(ctx context.Context, handset handsetdb.Handset) error {
89		m := bson.M{
90			"id": handset.ID,
91		}
92	
93		if handset.Name != "" {
94			m["name"] = handset.Name
95		}
96		if handset.RetailPrice != "" {
97			m["retailPrice"] = handset.RetailPrice
98		}
99		if handset.ContractPrice != "" {
100			m["contractPrice"] = handset.ContractPrice
101		}
102		if handset.ContractTerm != "" {
103			m["contractTerm"] = handset.ContractTerm
104		}
105		m["active"] = handset.Active
106		m["outOfStock"] = handset.OutOfStock
107	
108		_, err := s.handsetsCollection.
109			UpdateOne(ctx, bson.M{"id": handset.ID}, bson.M{"$set": m}, options.Update().SetUpsert(true))
110		if err != nil {
111			return fmt.Errorf("could not upsert handset: %w", err)
112		}
113		return nil
114	}
115	
116	// UpsertHandsetModel upserts a models.Handset with versioning support.
117	// When currentProperties.Version changes, the old properties are pushed into the versions array.
118	func (s storage) UpsertHandsetModel(ctx context.Context, handset models.Handset) error {
119		// Fetch the existing document to determine if currentProperties has changed
120		var existing models.Handset
121		err := s.handsetsCollection.FindOne(ctx, bson.M{"billID": handset.BillID}).Decode(&existing)
122		if err != nil && !errors.Is(err, mongo.ErrNoDocuments) {
123			return fmt.Errorf("could not fetch existing handset: %w", err)
124		}
125	
126		update := bson.M{}
127	
128		if err == nil {
129			// Document exists – push old currentProperties into versions if version changed
130			if existing.CurrentProperties.Version != "" && existing.CurrentProperties.Version != handset.CurrentProperties.Version {
131				update["$push"] = bson.M{"versions": existing.CurrentProperties}
132			}
133		}
134	
135		// Ensure newly inserted handsets have a stable UUID id.
136		update["$setOnInsert"] = bson.M{
137			"id": uuid.New(),
138		}
139	
140		update["$set"] = bson.M{
141			"billID":            handset.BillID,
142			"active":            handset.Active,
143			"currentProperties": handset.CurrentProperties,
144		}
145	
146		_, err = s.handsetsCollection.
147			UpdateOne(ctx, bson.M{"billID": handset.BillID}, update, options.Update().SetUpsert(true))
148		if err != nil {
149			return fmt.Errorf("could not upsert handset: %w", err)
150		}
151	
152		return nil
153	}
