262	func (s storage) UpdateContractStatusByID(ctx context.Context, contractID uuid.UUID, status models.ContractStatus) error {
263		filter := bson.M{"id": contractID}
264		return s.updateContractStatus(ctx, filter, status, expectedCurrentStatuses(status)...)
265	}
