267	func expectedCurrentStatuses(status models.ContractStatus) []models.ContractStatus {
268		switch status {
269		case models.ContractStatusEligibilityApproved, models.ContractStatusDeclined:
270			return []models.ContractStatus{models.ContractStatusPendingEligibility}
271		case models.ContractStatusApproved:
272			return []models.ContractStatus{models.ContractStatusEligibilityApproved}
273		case models.ContractStatusHandsetOrdered:
274			return []models.ContractStatus{models.ContractStatusApproved}
275		default:
276			return nil
277		}
278	}
