280	func (s storage) updateContractStatus(ctx context.Context, filter bson.M, status models.ContractStatus, currentStatuses ...models.ContractStatus) error {
281		if len(currentStatuses) == 1 {
282			filter["status"] = currentStatuses[0]
283		} else if len(currentStatuses) > 1 {
284			filter["status"] = bson.M{"$in": currentStatuses}
285		}
286		update := bson.M{
287			"$set": bson.M{
288				"status":    status,
289				"updatedAt": time.Now(),
290			},
291		}
292	
293		result, err := s.contractsCollection.UpdateOne(ctx, filter, update)
294		if err != nil {
295			return fmt.Errorf("could not update contract status: %w", err)
296		}
297		if result.MatchedCount == 0 {
298			if len(currentStatuses) > 0 {
299				return terrors.ErrConflict
300			}
301			return terrors.ErrNotFound
302		}
303		return nil
304	}
