package cron

import (
	"context"

	"github.com/utilitywarehouse/telecom-mobile/pkg/handsetdb"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
)

type EQDB interface {
	Close() error
	GetHandsets(ctx context.Context) ([]handsetdb.HandsetType, error)
}

type Storage interface {
	UpsertHandset(ctx context.Context, handset handsetdb.Handset) error
}

type handsetLoader struct {
	eqdb  EQDB
	store Storage
}

func NewHandsetLoader(eqdb EQDB, store Storage) *handsetLoader {
	return &handsetLoader{
		eqdb:  eqdb,
		store: store,
	}
}

func (h *handsetLoader) Run(ctx context.Context) {
	handsets, err := h.eqdb.GetHandsets(ctx)
	if err != nil {
		tlog.WithError(err).Error(ctx, "failed to get handsets from equinoxdb")
		return
	}

	for _, handset := range handsets {
		if err := h.store.UpsertHandset(ctx, handsetdb.HandsetTypeToHandset(handset)); err != nil {
			tlog.WithError(err).Error(ctx, "failed to upsert handset")
			return
		}
	}

	return
}

