package tpubsub

import (
	"fmt"

	"github.com/utilitywarehouse/protoc-gen-protostrate/protostrate"
	"github.com/utilitywarehouse/protoc-gen-protostrate/protostrate/interceptor/consumer"
	"github.com/utilitywarehouse/protoc-gen-protostrate/protostrate/interceptor/producer"
	"github.com/utilitywarehouse/protoc-gen-protostrate/protostrate/message"
	contracts "github.com/utilitywarehouse/telecom-contracts/go/proto"
	"github.com/utilitywarehouse/telecom-fixed-line/pkg/message/transients"
	protostrate_instrumented "github.com/utilitywarehouse/telecom-monorepo/pkg/prometheus/protostrate"
	"google.golang.org/protobuf/proto"

	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tvars"
)

// DefaultProtostrateConsumerOpts returns the default options for creating a protostrate consumer
func DefaultProtostrateConsumerOpts(appName string) []protostrate.ConsumerOption {
	return []protostrate.ConsumerOption{
		protostrate.WithConsumerInterceptor(protostrate_instrumented.NewConsumerMetrics()),
		// I don't know if this is actually used anywhere
		protostrate.WithConsumerInterceptor(consumer.NewFilterReplayTargetsInterceptor(fmt.Sprintf("%s-projector", appName))),
		protostrate.WithConsumerInterceptor(transients.ProtostrateInterceptor),
		protostrate.WithConsumerInterceptor(consumer.NewAuditCorrelationInterceptor()),
		protostrate.WithConsumerInterceptor(consumer.NewTokenCorrelationInterceptor()),
		WithConsumerEnvelopeTranslator(),
	}
}

func DefaultProtostrateProducerOpts(appName string) []protostrate.ProducerOption {
	return []protostrate.ProducerOption{
		protostrate.WithProducerInterceptor(producer.NewSenderDecoratorInterceptor(appName, tvars.Namespace, "")),
		protostrate.WithProducerInterceptor(protostrate_instrumented.NewProducerMetrics()),
		protostrate.WithProducerInterceptor(producer.NewTokenCorrelationInterceptor()),
		protostrate.WithProducerInterceptor(producer.NewAuditInterceptor()),
		WithProducerEnvelopeTranslator(),
	}
}

	tlog.WithAttribute("service_id", contract.ServiceID).
		WithAttribute("customer_id", contract.CustomerID).
		WithAttribute("contract_id", contract.ID.String()).
		WithAttribute("request_id", contract.RequestID).
		WithAttribute("handset_id", contract.HandsetID).
		Info(ctx, "handset contract created")

	// Produce lifecycle event
	if err := s.eventProducer.ProduceMobileHandsetContractRequestedSync(ctx, &serviceevents.MobileHandsetContractRequested{
		ServiceId:  contract.ServiceID,
		CustomerId: contract.CustomerID,
		ContractId: contract.ID.String(),
		HandsetId:  contract.HandsetID,
	}); err != nil {
		tlog.WithError(err).
			WithAttribute("contract_id", contract.ID.String()).
			Error(ctx, "failed to produce MobileHandsetContractRequested event")
	}

	redirectURL, err := eligibilityRedirectURL(s.eligibilityProviderURL, contract.RequestID)
	if err != nil {
		return "", "", err
	}

	return contract.RequestID, redirectURL, nil
}

// EligibilityCallbackSuccess handles the callback from the eligibility provider once the
// eligibility check has completed. The outcome.Decision field determines the result.
func (s *Service) EligibilityCallbackSuccess(ctx context.Context, requestID string, outcome models.EligibilityOutcome) error {

//
//handsetLoader := cron.NewHandsetLoader(eqdb, db)
//handsetLoaderSchedule := scheduler.NewCRONScheduler(ctx, 12*time.Hour, handsetLoader.Run)
//handsetLoaderSchedule.Start(true)

// Kafka producer for lifecycle events
kafkaSink := tpubsub.InitAsyncSink(ctx, tpubsub.PubSubSinkOpts{
	PubSubOpts: tpubsub.PubSubOpts{
		AppName: appName,
		Brokers: *cfg.kafkaBrokers,
		Topic:   *kafkaTopic,
		Version: *cfg.kafkaVersion,
	},
})
defer kafkaSink.Sink.Close()

protostrateProd := protostrate.NewProducer(
	protostrate_tools.NewAsyncSubstrateProducerDestination(kafkaSink.Sink),
	protostrate.WithProducerInterceptor(producer.NewSenderDecoratorInterceptor(appName, tvars.Namespace, "")),
	protostrate.WithProducerInterceptor(protostrate_instrumented.NewProducerMetrics()),
	protostrate.WithProducerInterceptor(producer.NewTokenCorrelationInterceptor()),
	protostrate.WithProducerInterceptor(producer.NewAuditInterceptor()),
	tpubsub.WithProducerEnvelopeTranslator(),
)
defer protostrateProd.Close()
go func() {
	if err := protostrateProd.Produce(ctx); err != nil {
		tlog.WithError(err).Fatal(ctx, "stopped producing messages")
	}
}()

eventProducer := events.NewProducer(serviceevents.NewServiceeventsProducer(protostrateProd))

iamMachine, err := machine.New()
if err != nil {
	tlog.
		WithError(err).
		Fatal(ctx, "failed to create machine provider")
}
defer func(iamMachine machine.Provider) {
	err := iamMachine.Close()
	if err != nil {
		tlog.
			WithError(err).
			Error(ctx, "failed to close machine provider")
	}
}(iamMachine)

opts := tgrpc.GetDefaultDialOptions()
opts.AddOptions(grpc.WithUnaryInterceptor(iam.UnaryClientInterceptor(iam.WithMachine(iamMachine))))

