package main

import (
	"context"
	"fmt"
	"os"
	"time"

	cli "github.com/jawher/mow.cli"
	"golang.org/x/sync/errgroup"
	"google.golang.org/api/option"
	"google.golang.org/api/sheets/v4"

	"github.com/utilitywarehouse/telecom-mobile/internal/shared/scheduler"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tbootstrap"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tgrpc"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tpubsub"
	tpubsubdeadletter "github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tpubsub/deadletter"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tstorage/tmongo"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tvars"
	"github.com/utilitywarehouse/telecom-mobile/services/account-gateway/pkg/protos/generated/v1/apis/accountgateway"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/consumer"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/loanbox"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/sheet"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/storage"
)

func startConsumerMode(ctx context.Context, eg *errgroup.Group, app *cli.Cli, cfg *sharedConfig) {
	kafkaTopicIn := app.String(cli.StringOpt{
		Name:   "kafka-topic-in",
		Desc:   "Kafka topic to consume lifecycle events from",
		EnvVar: "KAFKA_TOPIC_IN",
	})
	kafkaConsumerGroup := app.String(cli.StringOpt{
		Name:   "kafka-consumer-group",
		Desc:   "Kafka consumer group for the handset consumer",
		EnvVar: "KAFKA_CONSUMER_GROUP",
	})
	loanboxBaseURL := app.String(cli.StringOpt{
		Name:   "loanbox-base-url",
		Desc:   "Loanbox API base URL",
		EnvVar: "LOANBOX_BASE_URL",
	})
	loanboxAuthToken := app.String(cli.StringOpt{
		Name:   "loanbox-auth-token",
		Desc:   "Auth token for the Loanbox API",
		EnvVar: "LOANBOX_AUTH_TOKEN",
	})
	loanboxTimeout := app.String(cli.StringOpt{
		Name:   "loanbox-timeout",
		Desc:   "HTTP timeout for Loanbox API calls",
		EnvVar: "LOANBOX_TIMEOUT",
		Value:  "30s",
	})

	sheetID := *app.String(cli.StringOpt{
		Name:   "gsheet-id",
		Desc:   "Google Sheet ID",
		EnvVar: "GSHEET_ID",
	})

	sheetReadRange := *app.String(cli.StringOpt{
		Name:   "gsheet-read-range",
		Desc:   "Google Sheet read range",
		EnvVar: "GSHEET_READ_RANGE",
	})

	sheetCredentialsPath := *app.String(cli.StringOpt{
		Name:   "gsheet-creds-path",
		Desc:   "Google Sheet credentials path",
		EnvVar: "GSHEET_CREDS_PATH",
	})

	mongoDB, err := tmongo.InitMongoDB(ctx, tmongo.MongoOpts{
		Url:          *cfg.mongoURL,
		DatabaseName: *cfg.mongoDBName,
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise mongodb")
	}
	db, err := storage.NewStorage(ctx, *mongoDB)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create mongo store")
	}

	accountGatewayConn, err := tgrpc.InitGRPCConnection(ctx, *cfg.accountGatewayAddress, tgrpc.GetDefaultDialOptions())
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to connect to account-gateway")
	}
	defer accountGatewayConn.Close()
	accountClient := accountgateway.NewAccountGatewayClient(accountGatewayConn)

	loanboxTimeoutDuration, err := time.ParseDuration(*loanboxTimeout)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to parse loanbox timeout")
	}
	lbClient, err := loanbox.NewClient(*loanboxBaseURL, *loanboxAuthToken, loanboxTimeoutDuration)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create loanbox client")
	}

	deadletterTopic := fmt.Sprintf("%s-deadletters", *kafkaTopicIn)
	deadletterSink, err := tpubsub.InitSyncSink(tpubsub.PubSubSinkOpts{
		PubSubOpts: tpubsub.PubSubOpts{
			AppName:   appName,
			Namespace: tvars.Namespace,
			Version:   *cfg.kafkaVersion,
			Brokers:   *cfg.kafkaBrokers,
			Topic:     deadletterTopic,
		},
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "cannot init deadletter sink")
	}

	contractConsumer := consumer.New(db, accountClient, lbClient)
	lifecycleSource, protostrateConsumer := tpubsub.InitProtostrateMobileConsumerWithDeadletter(
		ctx,
		tpubsub.PubSubSourceOpts{
			PubSubOpts: tpubsub.PubSubOpts{
				AppName: appName,
				Brokers: *cfg.kafkaBrokers,
				Topic:   *kafkaTopicIn,
				Version: *cfg.kafkaVersion,
			},
			Offset:        tpubsub.Oldest,
			ConsumerGroup: *kafkaConsumerGroup,
		},
		contractConsumer,
		tpubsub.ProtostrateDeadletterOpts{
			Retries: tpubsubdeadletter.DefaultRetries,
			Config: tpubsubdeadletter.DeadletterConfig{
				OriginTopic:    *kafkaTopicIn,
				Consumer:       appName,
				PublishMessage: deadletterSink.PublishMessage,
			},
		},
	)
	defer lifecycleSource.Close()

	// Prepare Google Sheets service
	tlog.Info(ctx, "Prepare Google Sheets service")
	srv, err := sheets.NewService(ctx, option.WithCredentialsFile(sheetCredentialsPath))
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheets service")
	}

	sheetSvc, err := sheet.NewSheetService(sheetID, sheetReadRange, &sheet.ValueGetter{
		Svc: srv,
	}, db)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheet service")
	}

	// Run an initial update of handsets from the sheet before starting the scheduler
	tlog.Info(ctx, "Run initial update of handsets from sheet")
	sheetSvc.UpdateHandsets(ctx)

	// Setup scheduler for handset updates
	tlog.Info(ctx, "Setup scheduler for handset updates")
	handsetSchedule := scheduler.NewScheduler(ctx, sheetSvc.UpdateHandsets, 30*time.Second)

	// Start the handset scheduler
	tlog.Info(ctx, "Start the handset scheduler")
	handsetSchedule.Start()
	defer handsetSchedule.Stop()

	opsServer := tbootstrap.InitOpsServer(ctx, tbootstrap.OpsServerOpts{
		AppName:        appName,
		AppDescription: appDesc,
		Revision:       gitHash,
		Addr:           *cfg.opsAddress,
		Checkers: []tbootstrap.CheckerBuilder{
			&tbootstrap.KafkaChecker{
				Statuser:   lifecycleSource,
				SourceType: tbootstrap.KafkaSource,
				CheckName:  "handset-consumer-source",
			},
			&tbootstrap.KafkaChecker{
				Statuser:   deadletterSink,
				SourceType: tbootstrap.KafkaSink,
				CheckName:  "handset-deadletter-sink",
			},
		},
	})

	err = tbootstrap.StartBootstrapGroup(eg,
		tbootstrap.WithMongoClient(ctx, *mongoDB),
		tbootstrap.WithProtostrateConsumer(ctx, protostrateConsumer, *kafkaTopicIn),
		tbootstrap.WithSubstrateSyncProducer(ctx, deadletterSink, deadletterTopic),
		tbootstrap.WithOpsServer(ctx, opsServer),
	)
	if err != nil {
		tlog.WithError(err).Error(ctx, "error returned from error group")
		os.Exit(1)
	}
}

