package main

import (
	"context"
	"os"
	"time"

	cli "github.com/jawher/mow.cli"
	"golang.org/x/sync/errgroup"
	"google.golang.org/api/option"
	"google.golang.org/api/sheets/v4"

	"github.com/utilitywarehouse/telecom-mobile/internal/shared/scheduler"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tbootstrap"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tgrpc"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tstorage/tmongo"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/sheet"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/storage"
)

func startJobsMode(ctx context.Context, eg *errgroup.Group, app *cli.Cli, cfg *sharedConfig) {
	mongoDB, err := tmongo.InitMongoDB(ctx, tmongo.MongoOpts{
		Url:          *cfg.mongoURL,
		DatabaseName: *cfg.mongoDBName,
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise mongodb")
	}

	db, err := storage.NewStorage(ctx, *mongoDB)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create mongo store")
	}

	accountGatewayConn, err := tgrpc.InitGRPCConnection(ctx, *cfg.accountGatewayAddress, tgrpc.GetDefaultDialOptions())
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to connect to account-gateway")
	}
	defer accountGatewayConn.Close()

	// Prepare Google Sheets service
	tlog.Info(ctx, "Prepare Google Sheets service")
	srv, err := sheets.NewService(ctx, option.WithCredentialsFile(sheetCredentialsPath))
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheets service")
	}

	sheetSvc, err := sheet.NewSheetService(sheetID, sheetReadRange, &sheet.ValueGetter{
		Svc: srv,
	}, db)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheet service")
	}

	// Run an initial update of handsets from the sheet before starting the scheduler
	tlog.Info(ctx, "Run initial update of handsets from sheet")
	sheetSvc.UpdateHandsets(ctx)

	// Setup scheduler for handset updates
	tlog.Info(ctx, "Setup scheduler for handset updates")
	handsetSchedule := scheduler.NewScheduler(ctx, sheetSvc.UpdateHandsets, 30*time.Second)

	// Start the handset scheduler
	tlog.Info(ctx, "Start the handset scheduler")
	handsetSchedule.Start()
	defer handsetSchedule.Stop()

	opsServer := tbootstrap.InitOpsServer(ctx, tbootstrap.OpsServerOpts{
		AppName:        appName,
		AppDescription: appDesc,
		Revision:       gitHash,
		Addr:           *cfg.opsAddress,
		Checkers: []tbootstrap.CheckerBuilder{
			&tbootstrap.KafkaChecker{
				Statuser:   lifecycleSource,
				SourceType: tbootstrap.KafkaSource,
				CheckName:  "handset-consumer-source",
			},
			&tbootstrap.KafkaChecker{
				Statuser:   deadletterSink,
				SourceType: tbootstrap.KafkaSink,
				CheckName:  "handset-deadletter-sink",
			},
		},
	})

	err = tbootstrap.StartBootstrapGroup(eg,
		tbootstrap.WithMongoClient(ctx, *mongoDB),
		tbootstrap.WithProtostrateConsumer(ctx, protostrateConsumer, *kafkaTopicIn),
		tbootstrap.WithSubstrateSyncProducer(ctx, deadletterSink, deadletterTopic),
		tbootstrap.WithOpsServer(ctx, opsServer),
	)
	if err != nil {
		tlog.WithError(err).Error(ctx, "error returned from error group")
		os.Exit(1)
	}
}

package main

import (
	"os"

	cli "github.com/jawher/mow.cli"

	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tbootstrap"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/ttracing"
)

var gitHash string // populated at compile time

const appName = "handset"
const appDesc = "handset API"

const apiDesc = "provides API endpoints to get available handsets and request for a given service"
const consumerDesc = "starts the lifecycle consumer"

func main() {
	app := cli.App(appName, appDesc)

	eg, ctx, stop := tbootstrap.InitBootstrapGroup()
	defer stop()

	tlog.RegisterDefaultLogger()
	ttracing.MustRegisterTracing(ctx, appName, gitHash)

	cfg := registerSharedConfig(app)

	app.Command("api", apiDesc, func(cmd *cli.Cmd) {
		cmd.Action = func() {
			tlog.WithAttribute("mode", "api").Info(ctx, "starting application")
			startApiMode(ctx, eg, app, cfg)
		}
	})

	app.Command("consumer", consumerDesc, func(cmd *cli.Cmd) {
		cmd.Action = func() {
			tlog.WithAttribute("mode", "consumer").Info(ctx, "starting consumer")
			startConsumerMode(ctx, eg, app, cfg)
		}
	})

	app.Command("jobs", apiDesc, func(cmd *cli.Cmd) {
		cmd.Action = func() {
			tlog.WithAttribute("mode", "jobs").Info(ctx, "starting jobs scheduler")
			startApiMode(ctx, eg, app, cfg)
		}
	})

	app.Action = func() {
		app.PrintHelp()
		os.Exit(1)
	}

	if err := app.Run(os.Args); err != nil {
		tlog.WithError(err).Fatal(ctx, "unable to run app")
	}
}

package main

import (
	cli "github.com/jawher/mow.cli"
)

// sharedConfig holds CLI options that apply to every run mode (api, consumer).
// Mode-specific options stay with their startXxxMode function.
type sharedConfig struct {
	mongoURL              *string
	mongoDBName           *string
	kafkaBrokers          *[]string
	kafkaVersion          *string
	accountGatewayAddress *string
	opsAddress            *string
}

// registerSharedConfig registers the options that are shared across all run
// modes against the root cli.App, so they are parsed once regardless of which
// sub-command is invoked.
func registerSharedConfig(app *cli.Cli) *sharedConfig {
	return &sharedConfig{
		mongoURL: app.String(cli.StringOpt{
			Name:   "mongo-url",
			Desc:   "MongoDB connection URL",
			EnvVar: "MONGO_URL",
		}),
		mongoDBName: app.String(cli.StringOpt{
			Name:   "mongo-db-name",
			Desc:   "MongoDB database name",
			EnvVar: "MONGO_DB_NAME",
		}),
		kafkaBrokers: app.Strings(cli.StringsOpt{
			Name:   "kafka-brokers",
			Desc:   "Kafka broker addresses",
			EnvVar: "KAFKA_BROKERS",
		}),
		kafkaVersion: app.String(cli.StringOpt{
			Name:   "kafka-version",
			Desc:   "Kafka broker version",
			EnvVar: "KAFKA_VERSION",
		}),
		accountGatewayAddress: app.String(cli.StringOpt{
			Name:   "account-gateway-address",
			Desc:   "gRPC address for the account-gateway service",
			EnvVar: "ACCOUNT_GATEWAY_ADDRESS",
		}),
		opsAddress: app.String(cli.StringOpt{
			Name:   "ops-address",
			Desc:   "The address to listen on for ops server",
			EnvVar: "OPS_ADDRESS",
		}),
	}
}

