88	// UpsertHandset upserts a handset from the legacy equinoxdb/cron path (no versioning).
89	func (s storage) UpsertHandset(ctx context.Context, handset handsetdb.Handset) error {
90		m := bson.M{
91			"id": handset.ID,
92		}
93	
94		if handset.Name != "" {
95			m["name"] = handset.Name
96		}
97		if handset.RetailPrice != "" {
98			m["retailPrice"] = handset.RetailPrice
99		}
100		if handset.ContractPrice != "" {
101			m["contractPrice"] = handset.ContractPrice
102		}
103		if handset.ContractTerm != "" {
104			m["contractTerm"] = handset.ContractTerm
105		}
106		m["active"] = handset.Active
107		m["outOfStock"] = handset.OutOfStock
108	
109		_, err := s.handsetsCollection.
110			UpdateOne(ctx, bson.M{"id": handset.ID}, bson.M{"$set": m}, options.Update().SetUpsert(true))
111		if err != nil {
112			return fmt.Errorf("could not upsert handset: %w", err)
113		}
114		return nil
115	}
