117	// UpsertHandsetModel upserts a models.Handset with versioning support.
118	// When currentProperties.Version changes, the old properties are pushed into the versions array.
119	func (s storage) UpsertHandsetModel(ctx context.Context, handset models.Handset) error {
120		// Fetch the existing document to determine if currentProperties has changed
121		var existing models.Handset
122		err := s.handsetsCollection.FindOne(ctx, bson.M{"billID": handset.BillID}).Decode(&existing)
123		if err != nil && !errors.Is(err, mongo.ErrNoDocuments) {
124			return fmt.Errorf("could not fetch existing handset: %w", err)
125		}
126	
127		update := bson.M{}
128	
129		if err == nil {
130			// Document exists – push old currentProperties into versions if version changed
131			if existing.CurrentProperties.Version != "" && existing.CurrentProperties.Version != handset.CurrentProperties.Version {
132				update["$push"] = bson.M{"versions": existing.CurrentProperties}
133			}
134		}
135	
136		// Ensure newly inserted handsets have a stable UUID id.
137		update["$setOnInsert"] = bson.M{
138			"id": uuid.New(),
139		}
140	
141		update["$set"] = bson.M{
142			"billID":            handset.BillID,
143			"active":            handset.Active,
144			"currentProperties": handset.CurrentProperties,
145		}
146	
147		_, err = s.handsetsCollection.
148			UpdateOne(ctx, bson.M{"billID": handset.BillID}, update, options.Update().SetUpsert(true))
149		if err != nil {
150			return fmt.Errorf("could not upsert handset: %w", err)
151		}
152	
153		return nil
154	}
