156	func (s storage) GetHandsets(ctx context.Context, isInStock bool) ([]models.Handset, error) {
157		filter := bson.M{"active": true}
158		if isInStock {
159			filter["quantityInStock"] = bson.M{"$gt": 0}
160		}
161	
162		cur, err := s.handsetsCollection.Find(ctx, filter)
163		if err != nil {
164			return nil, fmt.Errorf("could not find handsets: %w", err)
165		}
166	
167		defer func(cur *mongo.Cursor, ctx context.Context) {
168			err := cur.Close(ctx)
169			if err != nil {
170				tlog.Error(ctx, "could not close cursor: %s", err.Error())
171			}
172		}(cur, ctx)
173	
174		var handsets []models.Handset
175		for cur.Next(ctx) {
176			var handset models.Handset
177			err := cur.Decode(&handset)
178			if err != nil {
179				return nil, fmt.Errorf("could not decode handset: %w", err)
180			}
181			handsets = append(handsets, handset)
182		}
183	
184		if err := cur.Err(); err != nil {
185			return nil, fmt.Errorf("error iterating over handsets: %w", err)
186		}
187	
188		return handsets, nil
189	}
