				Expect(err).To(MatchError(terrors.ErrNotFound))
				Expect(contract).To(BeNil())
			})
		})
	})

	Describe("UpdateContractStatus", func() {
		It("updates the contract status", func() {
			mockContracts.EXPECT().
				UpdateOne(gomock.Any(), gomock.Any(), gomock.Any()).
				Return(&mongo.UpdateResult{MatchedCount: 1, ModifiedCount: 1}, nil)

			err := store.UpdateContractStatus(ctx, "request-1", models.ContractStatusApproved)
			Expect(err).ToNot(HaveOccurred())
		})

		When("no contract matches the guarded transition", func() {
			It("returns ErrContractStatusConflict", func() {
				mockContracts.EXPECT().
					UpdateOne(gomock.Any(), gomock.Any(), gomock.Any()).
					Return(&mongo.UpdateResult{MatchedCount: 0}, nil)

				err := store.UpdateContractStatus(ctx, "nonexistent-request", models.ContractStatusDeclined)
				Expect(err).To(MatchError(terrors.ErrConflict))
			})
		})

		When("the update fails", func() {
			It("returns an error", func() {
				mockContracts.EXPECT().
					UpdateOne(gomock.Any(), gomock.Any(), gomock.Any()).
					Return(nil, errors.New("connection error"))

				err := store.UpdateContractStatus(ctx, "request-1", models.ContractStatusApproved)
				Expect(err).To(HaveOccurred())
				Expect(err.Error()).To(ContainSubstring("could not update contract status"))
			})
		})
	})
})

