package main

import (
	"context"
	"os"
	"time"

	cli "github.com/jawher/mow.cli"
	"github.com/utilitywarehouse/protoc-gen-protostrate/protostrate"
	"github.com/utilitywarehouse/protoc-gen-protostrate/protostrate/interceptor/producer"
	"github.com/utilitywarehouse/protoc-gen-protostrate/protostrate_tools"
	protostrate_instrumented "github.com/utilitywarehouse/telecom-monorepo/pkg/prometheus/protostrate"
	"golang.org/x/sync/errgroup"

	"github.com/utilitywarehouse/telecom-mobile/pkg/generated/protos/mobile/v1/events/serviceevents"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tbootstrap"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tpubsub"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tstorage/tmongo"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tvars"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/events"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/jobs"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/storage"
)

func startJobsMode(ctx context.Context, eg *errgroup.Group, app *cli.Cli, cfg *sharedConfig) {
	kafkaTopic := app.String(cli.StringOpt{
		Name:   "kafka-topic-out",
		Desc:   "Kafka topic to publish lifecycle events to",
		EnvVar: "KAFKA_TOPIC_OUT",
	})

	mongoDB, err := tmongo.InitMongoDB(ctx, tmongo.MongoOpts{
		Url:          *cfg.mongoURL,
		DatabaseName: *cfg.mongoDBName,
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise mongodb")
	}

	db, err := storage.NewStorage(ctx, *mongoDB, time.Now)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create mongo store")
	}

	// Kafka producer for lifecycle events
	kafkaSink := tpubsub.InitAsyncSink(ctx, tpubsub.PubSubSinkOpts{
		PubSubOpts: tpubsub.PubSubOpts{
			AppName: appName,
			Brokers: *cfg.kafkaBrokers,
			Topic:   *kafkaTopic,
			Version: *cfg.kafkaVersion,
		},
	})
	defer kafkaSink.Sink.Close()

	protostrateProd := protostrate.NewProducer(
		protostrate_tools.NewAsyncSubstrateProducerDestination(kafkaSink.Sink),
		protostrate.WithProducerInterceptor(producer.NewSenderDecoratorInterceptor(appName, tvars.Namespace, "")),
		protostrate.WithProducerInterceptor(protostrate_instrumented.NewProducerMetrics()),
		protostrate.WithProducerInterceptor(producer.NewTokenCorrelationInterceptor()),
		protostrate.WithProducerInterceptor(producer.NewAuditInterceptor()),
		tpubsub.WithProducerEnvelopeTranslator(),
	)
	defer protostrateProd.Close()
	go func() {
		if err := protostrateProd.Produce(ctx); err != nil {
			tlog.WithError(err).Fatal(ctx, "stopped producing messages")
		}
	}()

	_ = events.NewProducer(serviceevents.NewServiceeventsProducer(protostrateProd))

	// Setup scheduler for handset updates
	tlog.Info(ctx, "Setup scheduler for handset updates")
	jobs := jobs.New(ctx, db, protostrateProd)
	jobs.Start()
	defer jobs.Stop()

	opsServer := tbootstrap.InitOpsServer(ctx, tbootstrap.OpsServerOpts{
		AppName:        appName,
		AppDescription: appDesc,
		Revision:       gitHash,
		Addr:           *cfg.opsAddress,
	})

	err = tbootstrap.StartBootstrapGroup(eg,
		tbootstrap.WithMongoClient(ctx, *mongoDB),
		tbootstrap.WithProtostrateProducer(ctx, protostrateProd, *kafkaTopic),
		tbootstrap.WithOpsServer(ctx, opsServer),
	)
	if err != nil {
		tlog.WithError(err).Error(ctx, "error returned from error group")
		os.Exit(1)
	}
}

