package scheduler

import (
	"context"
	"sync"
	"time"

	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
)

type JobScheduler interface {
	Start()
	Stop()
}

type Scheduler struct {
	ticker     *time.Ticker
	busy       *sync.Mutex
	completion *sync.WaitGroup
	function   func(ctx context.Context)
	done       chan bool
	ctx        context.Context
}

func NewScheduler(ctx context.Context, function func(ctx context.Context), interval time.Duration) *Scheduler {
	ticker := time.NewTicker(interval)

	sched := &Scheduler{
		ctx:        ctx,
		ticker:     ticker,
		busy:       &sync.Mutex{},
		completion: &sync.WaitGroup{},
		done:       make(chan bool),
	}

	sched.function = function

	return sched
}

func (c *Scheduler) Start() {
	c.completion.Add(1)
	go func() {
		defer c.completion.Done()
		for {
			select {
			case <-c.ctx.Done():
				tlog.Info(c.ctx, "gracefully shutting down scheduler")
				return
			case <-c.done:
				return
			case <-c.ticker.C:
				c.completion.Add(1)
				go c.runTargetFunctionIfNotRunning()
			}
		}
	}()
}

func (c *Scheduler) Stop() {
	c.ticker.Stop()
	close(c.done)
	c.completion.Wait()
}

func (c *Scheduler) runTargetFunctionIfNotRunning() {
	defer c.completion.Done()

	if !c.busy.TryLock() {
		return // if the previous processing is still ongoing, we bail out
	}

	defer c.busy.Unlock()
	c.function(c.ctx)
}

