397	func (s storage) FindAndUpdateExpiredContracts(ctx context.Context) ([]models.Contract, error) {
398		filter := bson.M{
399			"status":    models.ContractStatusHandsetOrdered,
400			"expiresAt": bson.M{"$lte": s.nowFunc()},
