var testContractUUID = uuid.MustParse("22222222-2222-2222-2222-222222222222")

func TestConsumeMobileHandsetOrderedUpdatesContractStatus(t *testing.T) {
	t.Parallel()

	ctrl := gomock.NewController(t)
	store := mockConsumer.NewMockStorage(ctrl)
	consumerSvc := consumer.New(store, nil, nil)

	store.EXPECT().
		GetContractByID(gomock.Any(), testContractUUID).
		Return(&models.Contract{
			ID:     testContractUUID,
			Status: models.ContractStatusApproved,
		}, nil)

	store.EXPECT().
		UpdateContractStatusByID(gomock.Any(), testContractUUID, models.ContractStatusHandsetOrdered).
		Return(nil)

	acked := false
	err := consumerSvc.ConsumeMobileHandsetOrdered(
		context.Background(),
		&message.Envelope{Id: "event-1"},
		&serviceevents.MobileHandsetOrdered{
			ServiceId:  "service-1",
			CustomerId: "customer-1",
			ContractId: testContractUUID.String(),
			HandsetId:  "h-1",
		},
		func() error {
			acked = true
			return nil
		},
	)
	if err != nil {
		t.Fatalf("ConsumeMobileHandsetOrdered returned error: %v", err)
	}
	if !acked {
		t.Fatal("expected message to be acked")
	}
}

