)

func startApiMode(ctx context.Context, eg *errgroup.Group, app *cli.Cli, cfg *sharedConfig) {
	swaggerListenAddress := app.String(cli.StringOpt{
		Name:   "swagger listen address",
		Desc:   "The swagger listen address",
		EnvVar: "SWAGGER_LISTEN_ADDRESS",
	})
	grpcListenAddress := app.String(cli.StringOpt{
		Name:   "grpc-server-listen-address",
		Desc:   "The address to listen on for API GRPC connections",
		EnvVar: "GRPC_SERVER_LISTEN_ADDRESS",
	})
	//eqdbConnStr := app.String(cli.StringOpt{
	//	Name:   "equinoxdb-conn-str",
	//	Desc:   "EquinoxDB connection string",
	//	EnvVar: "EQUINOXDB_CONN_STR",
	//})
	maxMessageSize := app.Int(cli.IntOpt{
		Name:   "max-grpc-message-size",
		EnvVar: "MAX_GRPC_MESSAGE_SIZE_MB",
		Desc:   "max grpc message size in mb",
	})
	callbackSecret := app.String(cli.StringOpt{
		Name:   "eligibility-callback-secret",
		Desc:   "Shared secret to verify eligibility callback requests",
		EnvVar: "ELIGIBILITY_CALLBACK_SECRET",
	})
	eligibilityProviderURL := app.String(cli.StringOpt{
		Name:   "eligibility-provider-url",
		Desc:   "Third-party eligibility provider base URL",
		EnvVar: "ELIGIBILITY_PROVIDER_URL",
	})
	kafkaTopic := app.String(cli.StringOpt{
		Name:   "kafka-topic-out",
		Desc:   "Kafka topic to publish lifecycle events to",
		EnvVar: "KAFKA_TOPIC_OUT",
	})
	myServicesAddress := app.String(cli.StringOpt{
		Name:   "my-services-address",
		Desc:   "gRPC address for my-services",
		EnvVar: "MY_SERVICES_ADDRESS",
	})

	if err := validateAPIConfig(*callbackSecret, *eligibilityProviderURL); err != nil {
		tlog.WithError(err).Fatal(ctx, "invalid api configuration")
	}

	mongoDB, err := tmongo.InitMongoDB(ctx, tmongo.MongoOpts{
		Url:          *cfg.mongoURL,
		DatabaseName: *cfg.mongoDBName,
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise mongodb")
	}

	db, err := storage.NewStorage(ctx, *mongoDB)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create mongo store")
	}

	//eqdb, err := equinoxdb.New(*eqdbConnStr)
	//if err != nil {
	//	tlog.WithError(err).Fatal(ctx, "failed to connect to equinoxdb")
	//}
	//
	//handsetLoader := cron.NewHandsetLoader(eqdb, db)
	//handsetLoaderSchedule := scheduler.NewCRONScheduler(ctx, 12*time.Hour, handsetLoader.Run)
	//handsetLoaderSchedule.Start(true)

	// Kafka producer for lifecycle events
	kafkaSink := tpubsub.InitAsyncSink(ctx, tpubsub.PubSubSinkOpts{
		PubSubOpts: tpubsub.PubSubOpts{
			AppName: appName,
			Brokers: *cfg.kafkaBrokers,
			Topic:   *kafkaTopic,
			Version: *cfg.kafkaVersion,
		},
	})
	defer kafkaSink.Sink.Close()

	protostrateProd := protostrate.NewProducer(
		protostrate_tools.NewAsyncSubstrateProducerDestination(kafkaSink.Sink),
		protostrate.WithProducerInterceptor(producer.NewSenderDecoratorInterceptor(appName, tvars.Namespace, "")),
		protostrate.WithProducerInterceptor(protostrate_instrumented.NewProducerMetrics()),
		protostrate.WithProducerInterceptor(producer.NewTokenCorrelationInterceptor()),
		protostrate.WithProducerInterceptor(producer.NewAuditInterceptor()),
		tpubsub.WithProducerEnvelopeTranslator(),
	)
	defer protostrateProd.Close()
	go func() {
		if err := protostrateProd.Produce(ctx); err != nil {
			tlog.WithError(err).Fatal(ctx, "stopped producing messages")
		}
	}()

	eventProducer := events.NewProducer(serviceevents.NewServiceeventsProducer(protostrateProd))

	iamMachine, err := machine.New()
	if err != nil {
		tlog.
			WithError(err).
			Fatal(ctx, "failed to create machine provider")
	}
	defer func(iamMachine machine.Provider) {
		err := iamMachine.Close()
		if err != nil {
			tlog.
				WithError(err).
				Error(ctx, "failed to close machine provider")
		}
	}(iamMachine)

	opts := tgrpc.GetDefaultDialOptions()
	opts.AddOptions(grpc.WithUnaryInterceptor(iam.UnaryClientInterceptor(iam.WithMachine(iamMachine))))
	accountGatewayConn, err := tgrpc.InitGRPCConnection(ctx, *cfg.accountGatewayAddress, opts)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to connect to account-gateway")
	}

	defer accountGatewayConn.Close()
	accountClient := accountgateway.NewAccountGatewayClient(accountGatewayConn)

	myServicesConn, err := tgrpc.InitGRPCConnection(ctx, *myServicesAddress, tgrpc.GetDefaultDialOptions())
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to connect to my-services-api")
	}

	defer myServicesConn.Close()
	myServicesClient := myservicesapi.NewServiceClient(myServicesConn)

	handsetService := service.NewService(db, eventProducer, accountClient, myServicesClient, *eligibilityProviderURL)
	handsetAPI := grpchandler.NewController(handsetService, *callbackSecret)

	swaggerAPI, err := tgrpc.InitSwaggerAPIWithMuxes(ctx, tgrpc.EmbedSwagger{Static: swagger.Static}, handset.RegisterHandsetAPIHandlerFromEndpoint, maxMessageSize, swaggerListenAddress, grpcListenAddress,
		runtime.WithIncomingHeaderMatcher(func(key string) (string, bool) {
			if strings.EqualFold(key, "x-callback-secret") {
				return "x-callback-secret", true
			}
			return runtime.DefaultHeaderMatcher(key)
		}))

	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise swagger api")
	}
	grpcOpts := tgrpc.GetDefaultServerOptions()
	grpcOpts.AddOptions(tgrpc.WithGRPCServerAddress(*grpcListenAddress), tgrpc.WithGRPCMaxRecvMsgSize(*maxMessageSize))

	grpcServer := tgrpc.InitGRPCServer(&handset.HandsetAPI_ServiceDesc, handsetAPI, grpcOpts)
	opsServer := tbootstrap.InitOpsServer(ctx, tbootstrap.OpsServerOpts{
		AppName:        appName,
		AppDescription: appDesc,
		Revision:       gitHash,
		Addr:           *cfg.opsAddress,
		Checkers: []tbootstrap.CheckerBuilder{
			&tbootstrap.GrpcChecker{
				GrpcServerListenAddress: *grpcListenAddress,
			},
		},
	})

	err = tbootstrap.StartBootstrapGroup(eg,
		tbootstrap.WithOpsServer(ctx, opsServer),
		tbootstrap.WithMongoClient(ctx, *mongoDB),
		tbootstrap.WithGrpcServer(ctx, grpcServer),
		tbootstrap.WithWaitableHttpServer(ctx, swaggerAPI, tvars.SwaggerLabel),
		tbootstrap.WithProtostrateProducer(ctx, protostrateProd, *kafkaTopic),
		tbootstrap.WithGRPCClient(ctx, accountGatewayConn),
		tbootstrap.WithGRPCClient(ctx, myServicesConn),
		tbootstrap.WithMachineToken(ctx, iamMachine),
		//tbootstrap.WithHandledGoRoutine(ctx, func() error {
		//	<-ctx.Done()
		//	handsetLoaderSchedule.Stop()
		//	if err := eqdb.Close(); err != nil {
		//		tlog.WithError(err).Error(ctx, "failed to close equinoxdb")
		//	}
		//	return nil
		//}),
	)

	if err != nil {
		tlog.WithError(err).Error(ctx, "error returned from error group")
	}
}

func validateAPIConfig(callbackSecret, eligibilityProviderURL string) error {
	if strings.TrimSpace(callbackSecret) == "" {
		return fmt.Errorf("eligibility callback secret is required")
	}

	u, err := url.ParseRequestURI(eligibilityProviderURL)
	if err != nil {
		return fmt.Errorf("eligibility provider URL is invalid: %w", err)
	}
	if u.Scheme != "https" || u.Host == "" {
		return fmt.Errorf("eligibility provider URL must be an absolute https URL")
	}

	return nil
}

package main

import (
	"context"
	"fmt"
	"os"
	"time"

	cli "github.com/jawher/mow.cli"
	"golang.org/x/sync/errgroup"
	"google.golang.org/api/option"
	"google.golang.org/api/sheets/v4"

	"github.com/utilitywarehouse/telecom-mobile/internal/shared/scheduler"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tbootstrap"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tgrpc"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tlog"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tpubsub"
	tpubsubdeadletter "github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tpubsub/deadletter"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tstorage/tmongo"
	"github.com/utilitywarehouse/telecom-mobile/pkg/libdry/tvars"
	"github.com/utilitywarehouse/telecom-mobile/services/account-gateway/pkg/protos/generated/v1/apis/accountgateway"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/consumer"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/loanbox"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/sheet"
	"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/storage"
)

func startConsumerMode(ctx context.Context, eg *errgroup.Group, app *cli.Cli, cfg *sharedConfig) {
	kafkaTopicIn := app.String(cli.StringOpt{
		Name:   "kafka-topic-in",
		Desc:   "Kafka topic to consume lifecycle events from",
		EnvVar: "KAFKA_TOPIC_IN",
	})
	kafkaConsumerGroup := app.String(cli.StringOpt{
		Name:   "kafka-consumer-group",
		Desc:   "Kafka consumer group for the handset consumer",
		EnvVar: "KAFKA_CONSUMER_GROUP",
	})
	loanboxBaseURL := app.String(cli.StringOpt{
		Name:   "loanbox-base-url",
		Desc:   "Loanbox API base URL",
		EnvVar: "LOANBOX_BASE_URL",
	})
	loanboxAuthToken := app.String(cli.StringOpt{
		Name:   "loanbox-auth-token",
		Desc:   "Auth token for the Loanbox API",
		EnvVar: "LOANBOX_AUTH_TOKEN",
	})
	loanboxTimeout := app.String(cli.StringOpt{
		Name:   "loanbox-timeout",
		Desc:   "HTTP timeout for Loanbox API calls",
		EnvVar: "LOANBOX_TIMEOUT",
		Value:  "30s",
	})

	sheetID := *app.String(cli.StringOpt{
		Name:   "gsheet-id",
		Desc:   "Google Sheet ID",
		EnvVar: "GSHEET_ID",
	})

	sheetReadRange := *app.String(cli.StringOpt{
		Name:   "gsheet-read-range",
		Desc:   "Google Sheet read range",
		EnvVar: "GSHEET_READ_RANGE",
	})

	sheetCredentialsPath := *app.String(cli.StringOpt{
		Name:   "gsheet-creds-path",
		Desc:   "Google Sheet credentials path",
		EnvVar: "GSHEET_CREDS_PATH",
	})

	mongoDB, err := tmongo.InitMongoDB(ctx, tmongo.MongoOpts{
		Url:          *cfg.mongoURL,
		DatabaseName: *cfg.mongoDBName,
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise mongodb")
	}
	db, err := storage.NewStorage(ctx, *mongoDB)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create mongo store")
	}

	accountGatewayConn, err := tgrpc.InitGRPCConnection(ctx, *cfg.accountGatewayAddress, tgrpc.GetDefaultDialOptions())
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to connect to account-gateway")
	}
	defer accountGatewayConn.Close()
	accountClient := accountgateway.NewAccountGatewayClient(accountGatewayConn)

	loanboxTimeoutDuration, err := time.ParseDuration(*loanboxTimeout)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to parse loanbox timeout")
	}
	lbClient, err := loanbox.NewClient(*loanboxBaseURL, *loanboxAuthToken, loanboxTimeoutDuration)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create loanbox client")
	}

	deadletterTopic := fmt.Sprintf("%s-deadletters", *kafkaTopicIn)
	deadletterSink, err := tpubsub.InitSyncSink(tpubsub.PubSubSinkOpts{
		PubSubOpts: tpubsub.PubSubOpts{
			AppName:   appName,
			Namespace: tvars.Namespace,
			Version:   *cfg.kafkaVersion,
			Brokers:   *cfg.kafkaBrokers,
			Topic:     deadletterTopic,
		},
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "cannot init deadletter sink")
	}

	contractConsumer := consumer.New(db, accountClient, lbClient)
	lifecycleSource, protostrateConsumer := tpubsub.InitProtostrateMobileConsumerWithDeadletter(
		ctx,
		tpubsub.PubSubSourceOpts{
			PubSubOpts: tpubsub.PubSubOpts{
				AppName: appName,
				Brokers: *cfg.kafkaBrokers,
				Topic:   *kafkaTopicIn,
				Version: *cfg.kafkaVersion,
			},
			Offset:        tpubsub.Oldest,
			ConsumerGroup: *kafkaConsumerGroup,
		},
		contractConsumer,
		tpubsub.ProtostrateDeadletterOpts{
			Retries: tpubsubdeadletter.DefaultRetries,
			Config: tpubsubdeadletter.DeadletterConfig{
				OriginTopic:    *kafkaTopicIn,
				Consumer:       appName,
				PublishMessage: deadletterSink.PublishMessage,
			},
		},
	)
	defer lifecycleSource.Close()

	// Prepare Google Sheets service
	tlog.Info(ctx, "Prepare Google Sheets service")
	srv, err := sheets.NewService(ctx, option.WithCredentialsFile(sheetCredentialsPath))
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheets service")
	}

	sheetSvc, err := sheet.NewSheetService(sheetID, sheetReadRange, &sheet.ValueGetter{
		Svc: srv,
	}, db)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheet service")
	}

	// Run an initial update of handsets from the sheet before starting the scheduler
	tlog.Info(ctx, "Run initial update of handsets from sheet")
	sheetSvc.UpdateHandsets(ctx)

	// Setup scheduler for handset updates
	tlog.Info(ctx, "Setup scheduler for handset updates")
	handsetSchedule := scheduler.NewScheduler(ctx, sheetSvc.UpdateHandsets, 30*time.Second)

	// Start the handset scheduler
	tlog.Info(ctx, "Start the handset scheduler")
	handsetSchedule.Start()
	defer handsetSchedule.Stop()

	opsServer := tbootstrap.InitOpsServer(ctx, tbootstrap.OpsServerOpts{
		AppName:        appName,
		AppDescription: appDesc,
		Revision:       gitHash,
		Addr:           *cfg.opsAddress,
		Checkers: []tbootstrap.CheckerBuilder{
			&tbootstrap.KafkaChecker{
				Statuser:   lifecycleSource,
				SourceType: tbootstrap.KafkaSource,
				CheckName:  "handset-consumer-source",
			},
			&tbootstrap.KafkaChecker{
				Statuser:   deadletterSink,
				SourceType: tbootstrap.KafkaSink,
				CheckName:  "handset-deadletter-sink",
			},
		},
	})

	err = tbootstrap.StartBootstrapGroup(eg,
		tbootstrap.WithMongoClient(ctx, *mongoDB),
		tbootstrap.WithProtostrateConsumer(ctx, protostrateConsumer, *kafkaTopicIn),
		tbootstrap.WithSubstrateSyncProducer(ctx, deadletterSink, deadletterTopic),
		tbootstrap.WithOpsServer(ctx, opsServer),
	)
	if err != nil {
		tlog.WithError(err).Error(ctx, "error returned from error group")
		os.Exit(1)
	}
}

