func startApiMode(ctx context.Context, eg *errgroup.Group, app *cli.Cli, cfg *sharedConfig) {
	swaggerListenAddress := app.String(cli.StringOpt{
		Name:   "swagger listen address",
		Desc:   "The swagger listen address",
		EnvVar: "SWAGGER_LISTEN_ADDRESS",
	})
	grpcListenAddress := app.String(cli.StringOpt{
		Name:   "grpc-server-listen-address",
		Desc:   "The address to listen on for API GRPC connections",
		EnvVar: "GRPC_SERVER_LISTEN_ADDRESS",
	})
	//eqdbConnStr := app.String(cli.StringOpt{
	//	Name:   "equinoxdb-conn-str",
	//	Desc:   "EquinoxDB connection string",
	//	EnvVar: "EQUINOXDB_CONN_STR",
	//})
	maxMessageSize := app.Int(cli.IntOpt{
		Name:   "max-grpc-message-size",
		EnvVar: "MAX_GRPC_MESSAGE_SIZE_MB",
		Desc:   "max grpc message size in mb",
	})
	callbackSecret := app.String(cli.StringOpt{
		Name:   "eligibility-callback-secret",
		Desc:   "Shared secret to verify eligibility callback requests",
		EnvVar: "ELIGIBILITY_CALLBACK_SECRET",
	})
	eligibilityProviderURL := app.String(cli.StringOpt{
		Name:   "eligibility-provider-url",
		Desc:   "Third-party eligibility provider base URL",
		EnvVar: "ELIGIBILITY_PROVIDER_URL",
	})
	kafkaTopic := app.String(cli.StringOpt{
		Name:   "kafka-topic-out",
		Desc:   "Kafka topic to publish lifecycle events to",
		EnvVar: "KAFKA_TOPIC_OUT",
	})
	myServicesAddress := app.String(cli.StringOpt{
		Name:   "my-services-address",
		Desc:   "gRPC address for my-services",
		EnvVar: "MY_SERVICES_ADDRESS",
	})

	if err := validateAPIConfig(*callbackSecret, *eligibilityProviderURL); err != nil {
		tlog.WithError(err).Fatal(ctx, "invalid api configuration")
	}

	mongoDB, err := tmongo.InitMongoDB(ctx, tmongo.MongoOpts{
		Url:          *cfg.mongoURL,
		DatabaseName: *cfg.mongoDBName,
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise mongodb")
	}

	db, err := storage.NewStorage(ctx, *mongoDB, time.Now)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create mongo store")
	}

	//eqdb, err := equinoxdb.New(*eqdbConnStr)
	//if err != nil {
	//	tlog.WithError(err).Fatal(ctx, "failed to connect to equinoxdb")
	//}
	//
	//handsetLoader := cron.NewHandsetLoader(eqdb, db)
	//handsetLoaderSchedule := scheduler.NewCRONScheduler(ctx, 12*time.Hour, handsetLoader.Run)
	//handsetLoaderSchedule.Start(true)

	// Kafka producer for lifecycle events
	kafkaSink := tpubsub.InitAsyncSink(ctx, tpubsub.PubSubSinkOpts{
		PubSubOpts: tpubsub.PubSubOpts{
			AppName: appName,
			Brokers: *cfg.kafkaBrokers,
			Topic:   *kafkaTopic,
			Version: *cfg.kafkaVersion,
		},
	})
	defer kafkaSink.Sink.Close()

	protostrateProd := protostrate.NewProducer(
		protostrate_tools.NewAsyncSubstrateProducerDestination(kafkaSink.Sink),
		protostrate.WithProducerInterceptor(producer.NewSenderDecoratorInterceptor(appName, tvars.Namespace, "")),
		protostrate.WithProducerInterceptor(protostrate_instrumented.NewProducerMetrics()),
		protostrate.WithProducerInterceptor(producer.NewTokenCorrelationInterceptor()),
		protostrate.WithProducerInterceptor(producer.NewAuditInterceptor()),
		tpubsub.WithProducerEnvelopeTranslator(),
	)
	defer protostrateProd.Close()
	go func() {
		if err := protostrateProd.Produce(ctx); err != nil {
			tlog.WithError(err).Fatal(ctx, "stopped producing messages")
		}
	}()

	eventProducer := events.NewProducer(serviceevents.NewServiceeventsProducer(protostrateProd))

	iamMachine, err := machine.New()
	if err != nil {
		tlog.
			WithError(err).
			Fatal(ctx, "failed to create machine provider")
	}
	defer func(iamMachine machine.Provider) {
		err := iamMachine.Close()
		if err != nil {
			tlog.
				WithError(err).
				Error(ctx, "failed to close machine provider")
		}
	}(iamMachine)

	opts := tgrpc.GetDefaultDialOptions()
	opts.AddOptions(grpc.WithUnaryInterceptor(iam.UnaryClientInterceptor(iam.WithMachine(iamMachine))))
	accountGatewayConn, err := tgrpc.InitGRPCConnection(ctx, *cfg.accountGatewayAddress, opts)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to connect to account-gateway")
	}

	defer accountGatewayConn.Close()
	accountClient := accountgateway.NewAccountGatewayClient(accountGatewayConn)

	myServicesConn, err := tgrpc.InitGRPCConnection(ctx, *myServicesAddress, tgrpc.GetDefaultDialOptions())
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to connect to my-services-api")
	}

	defer myServicesConn.Close()
	myServicesClient := myservicesapi.NewServiceClient(myServicesConn)

	handsetService := service.NewService(db, eventProducer, accountClient, myServicesClient, *eligibilityProviderURL)
	handsetAPI := grpchandler.NewController(handsetService, *callbackSecret)

	swaggerAPI, err := tgrpc.InitSwaggerAPIWithMuxes(ctx, tgrpc.EmbedSwagger{Static: swagger.Static}, handset.RegisterHandsetAPIHandlerFromEndpoint, maxMessageSize, swaggerListenAddress, grpcListenAddress,
		runtime.WithIncomingHeaderMatcher(func(key string) (string, bool) {
			if strings.EqualFold(key, "x-callback-secret") {
				return "x-callback-secret", true
			}
			return runtime.DefaultHeaderMatcher(key)
		}))

	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to initialise swagger api")
	}
	grpcOpts := tgrpc.GetDefaultServerOptions()
	grpcOpts.AddOptions(tgrpc.WithGRPCServerAddress(*grpcListenAddress), tgrpc.WithGRPCMaxRecvMsgSize(*maxMessageSize))

	grpcServer := tgrpc.InitGRPCServer(&handset.HandsetAPI_ServiceDesc, handsetAPI, grpcOpts)
	opsServer := tbootstrap.InitOpsServer(ctx, tbootstrap.OpsServerOpts{
		AppName:        appName,
