		tbootstrap.WithProtostrateProducer(ctx, protostrateProd, *kafkaTopic),
		tbootstrap.WithGRPCClient(ctx, accountGatewayConn),
		tbootstrap.WithGRPCClient(ctx, myServicesConn),
		tbootstrap.WithMachineToken(ctx, iamMachine),
		//tbootstrap.WithHandledGoRoutine(ctx, func() error {
		//	<-ctx.Done()
		//	handsetLoaderSchedule.Stop()
		//	if err := eqdb.Close(); err != nil {
		//		tlog.WithError(err).Error(ctx, "failed to close equinoxdb")
		//	}
		//	return nil
		//}),
	)

	if err != nil {
		tlog.WithError(err).Error(ctx, "error returned from error group")
	}
}

func validateAPIConfig(callbackSecret, eligibilityProviderURL string) error {
	if strings.TrimSpace(callbackSecret) == "" {
		return fmt.Errorf("eligibility callback secret is required")
	}

	u, err := url.ParseRequestURI(eligibilityProviderURL)
	if err != nil {
		return fmt.Errorf("eligibility provider URL is invalid: %w", err)
	}
	if u.Scheme != "https" || u.Host == "" {
		return fmt.Errorf("eligibility provider URL must be an absolute https URL")
	}

	return nil
}

