	}

	deadletterTopic := fmt.Sprintf("%s-deadletters", *kafkaTopicIn)
	deadletterSink, err := tpubsub.InitSyncSink(tpubsub.PubSubSinkOpts{
		PubSubOpts: tpubsub.PubSubOpts{
			AppName:   appName,
			Namespace: tvars.Namespace,
			Version:   *cfg.kafkaVersion,
			Brokers:   *cfg.kafkaBrokers,
			Topic:     deadletterTopic,
		},
	})
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "cannot init deadletter sink")
	}

	contractConsumer := consumer.New(db, accountClient, lbClient)
	lifecycleSource, protostrateConsumer := tpubsub.InitProtostrateMobileConsumerWithDeadletter(
		ctx,
		tpubsub.PubSubSourceOpts{
			PubSubOpts: tpubsub.PubSubOpts{
				AppName: appName,
				Brokers: *cfg.kafkaBrokers,
				Topic:   *kafkaTopicIn,
				Version: *cfg.kafkaVersion,
			},
			Offset:        tpubsub.Oldest,
			ConsumerGroup: *kafkaConsumerGroup,
		},
		contractConsumer,
		tpubsub.ProtostrateDeadletterOpts{
			Retries: tpubsubdeadletter.DefaultRetries,
			Config: tpubsubdeadletter.DeadletterConfig{
				OriginTopic:    *kafkaTopicIn,
				Consumer:       appName,
				PublishMessage: deadletterSink.PublishMessage,
			},
		},
	)
	defer lifecycleSource.Close()

	// Prepare Google Sheets service
	tlog.Info(ctx, "Prepare Google Sheets service")
	srv, err := sheets.NewService(ctx, option.WithCredentialsFile(sheetCredentialsPath))
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheets service")
	}

	sheetSvc, err := sheet.NewSheetService(sheetID, sheetReadRange, &sheet.ValueGetter{
		Svc: srv,
	}, db)
	if err != nil {
		tlog.WithError(err).Fatal(ctx, "failed to create sheet service")
	}

	// Run an initial update of handsets from the sheet before starting the scheduler
	tlog.Info(ctx, "Run initial update of handsets from sheet")
	sheetSvc.UpdateHandsets(ctx)

	// Setup scheduler for handset updates
	tlog.Info(ctx, "Setup scheduler for handset updates")
	handsetSchedule := scheduler.NewScheduler(ctx, sheetSvc.UpdateHandsets, 30*time.Second)

	// Start the handset scheduler
	tlog.Info(ctx, "Start the handset scheduler")
	handsetSchedule.Start()
	defer handsetSchedule.Stop()

	opsServer := tbootstrap.InitOpsServer(ctx, tbootstrap.OpsServerOpts{
		AppName:        appName,
		AppDescription: appDesc,
		Revision:       gitHash,
		Addr:           *cfg.opsAddress,
		Checkers: []tbootstrap.CheckerBuilder{
			&tbootstrap.KafkaChecker{
				Statuser:   lifecycleSource,
				SourceType: tbootstrap.KafkaSource,
				CheckName:  "handset-consumer-source",
			},
			&tbootstrap.KafkaChecker{
				Statuser:   deadletterSink,
				SourceType: tbootstrap.KafkaSink,
				CheckName:  "handset-deadletter-sink",
			},
		},
	})

	err = tbootstrap.StartBootstrapGroup(eg,
		tbootstrap.WithMongoClient(ctx, *mongoDB),
		tbootstrap.WithProtostrateConsumer(ctx, protostrateConsumer, *kafkaTopicIn),
		tbootstrap.WithSubstrateSyncProducer(ctx, deadletterSink, deadletterTopic),
		tbootstrap.WithOpsServer(ctx, opsServer),
	)
	if err != nil {
		tlog.WithError(err).Error(ctx, "error returned from error group")
		os.Exit(1)
	}
}

